      "keystrokes": "cat > /app/decompress.py << 'PY'
#!/usr/bin/env python3
import sys
import os
import json
from pathlib import Path

def ensure_dir(path: Path):
    path.mkdir(parents=True, exist_ok=True)

def rm_tree(path: Path):
    if not path.exists():
        return
    if path.is_file() or path.is_symlink():
        path.unlink()
        return
    for root, dirs, files in os.walk(path, topdown=False):
        for f in files:
            Path(root, f).unlink()
        for d in dirs:
            Path(root, d).rmdir()
    path.rmdir()

def main():
    if len(sys.argv) != 2:
        print(f"Usage: python {__file__} <resharded_dir>")
        sys.exit(1)
    resharded_dir = Path(sys.argv[1]).resolve()
    if not resharded_dir.exists() or not resharded_dir.is_dir():
        print("Resharded directory does not exist or is not a directory", file=sys.stderr)
        sys.exit(2)

    manifest_path = resharded_dir / "manifest.json"
    if not manifest_path.exists():
        print("manifest.json not found in resharded_dir", file=sys.stderr)
        sys.exit(3)

    with open(manifest_path, 'r', encoding='utf-8') as mf:
        manifest = json.load(mf)

    files = manifest.get("files", {})
    empty_dirs = manifest.get("empty_dirs", [])

    if not isinstance(files, dict) or len(files) == 0:
        print("Manifest contains no files to reconstruct; aborting to avoid data loss.", file=sys.stderr)
        sys.exit(4)

    # Verify all referenced chunk files exist before starting
    for orig_rel, info in files.items():
        chunks = info.get("chunks", [])
        if len(chunks) == 0:
            print(f"No chunks listed for {orig_rel}; aborting.", file=sys.stderr)
            sys.exit(5)
        for ch in chunks:
            relpath = ch.get("relpath")
            if relpath is None:
                print(f"Missing relpath in manifest for {orig_rel} chunk {ch.get('index')}", file=sys.stderr)
                sys.exit(6)
            chunk_path = resharded_dir / relpath
            if not chunk_path.exists():
                print(f"Chunk file missing: {chunk_path}", file=sys.stderr)
                sys.exit(7)

    tmp_root = resharded_dir / ".reconstruct_tmp"
    if tmp_root.exists():
        rm_tree(tmp_root)
    ensure_dir(tmp_root)

    reconstructed_count = 0
    # Reconstruct files
    for orig_rel, info in files.items():
        out_path = tmp_root / orig_rel
        ensure_dir(out_path.parent)
        with open(out_path, 'wb') as out:
            chunks = sorted(info.get("chunks", []), key=lambda c: c.get("index", 0))
            for ch in chunks:
                chunk_path = resharded_dir / ch["relpath"]
                with open(chunk_path, 'rb') as cf:
                    out.write(cf.read())
        reconstructed_count += 1

    # Recreate empty directories
    for d in empty_dirs:
        ensure_dir(tmp_root / d)

    # Validate reconstruction count
    if reconstructed_count != len(files):
        print(f"Reconstructed {reconstructed_count} files, expected {len(files)}; aborting replacement.", file=sys.stderr)
        sys.exit(8)

    # Replace resharded_dir contents with reconstructed originals
    for entry in resharded_dir.iterdir():
        if entry.name == ".reconstruct_tmp":
            continue
        rm_tree(entry)

    # Move contents of tmp_root to resharded_dir
    for entry in tmp_root.iterdir():
        target = resharded_dir / entry.name
        if entry.is_dir():
            # Copy directory tree
            for src_root, dirnames, filenames in os.walk(entry):
                rel = Path(src_root).relative_to(entry)
                dst_root = target / rel
                ensure_dir(dst_root)
                for d in dirnames:
                    ensure_dir(dst_root / d)
                for f in filenames:
                    sp = Path(src_root) / f
                    dp = dst_root / f
                    dp.write_bytes(sp.read_bytes())
            rm_tree(entry)
        else:
            target.write_bytes(entry.read_bytes())
            entry.unlink()

    tmp_root.rmdir()

    print("Decompression complete: original structure restored in-place.")

if __name__ == '__main__':
    main()
PY
